  1	import * as _ from 'lodash-es';
  2	import {
  3	  PrometheusEndpoint,
  4	  RedExclamationCircleIcon,
  5	  useActiveNamespace,
  6	  useResolvedExtensions,
  7	} from '@openshift-console/dynamic-plugin-sdk';
  8	import {
  9	  Tooltip,
 10	  Select,
 11	  SelectOption,
 12	  MenuToggle,
 13	  MenuToggleElement,
 14	} from '@patternfly/react-core';
 15	import * as React from 'react';
 16	import { useTranslation } from 'react-i18next';
 17	import { useDispatch, useSelector } from 'react-redux';
 18	import { Map as ImmutableMap } from 'immutable';
 19	
 20	import { SingleTypeaheadDropdown } from '../../console/utils/single-typeahead-dropdown';
 21	import { getPrometheusURL } from '../../console/graphs/helpers';
 22	import { getQueryArgument, setQueryArgument } from '../../console/utils/router';
 23	import { useSafeFetch } from '../../console/utils/safe-fetch-hook';
 24	
 25	import {
 26	  dashboardsPatchVariable,
 27	  dashboardsVariableOptionsLoaded,
 28	  Perspective,
 29	} from '../../../actions/observe';
 30	import { getTimeRanges, isTimeoutError, QUERY_CHUNK_SIZE } from '../../utils';
 31	import { getLegacyObserveState, usePerspective } from '../../hooks/usePerspective';
 32	import { MonitoringState } from '../../../reducers/observe';
 33	import {
 34	  DEFAULT_GRAPH_SAMPLES,
 35	  MONITORING_DASHBOARDS_VARIABLE_ALL_OPTION_KEY,
 36	} from '../shared/utils';
 37	import {
 38	  DataSource,
 39	  isDataSource,
 40	} from '@openshift-console/dynamic-plugin-sdk/lib/extensions/dashboard-data-source';
 41	
 42	const intervalVariableRegExps = ['__interval', '__rate_interval', '__auto_interval_[a-z]+'];
 43	
 44	const isIntervalVariable = (itemKey: string): boolean =>
 45	  _.some(intervalVariableRegExps, (re) => itemKey?.match(new RegExp(`\\$${re}`, 'g')));
 46	
 47	export const evaluateVariableTemplate = (
 48	  template: string,
 49	  variables: ImmutableMap<string, Variable>,
 50	  timespan: number,
 51	): string => {
 52	  if (_.isEmpty(template)) {
 53	    return undefined;
 54	  }
 55	
 56	  const range: Variable = { value: `${Math.floor(timespan / 1000)}s` };
 57	  const allVariables = {
 58	    ...variables.toJS(),
 59	    __range: range,
 60	    /* eslint-disable camelcase */
 61	    __range_ms: range,
 62	    __range_s: range,
 63	    /* eslint-enable camelcase */
 64	  };
 65	
 66	  // Handle the special "interval" variables
 67	  const intervalMS = timespan / DEFAULT_GRAPH_SAMPLES;
 68	  const intervalMinutes = Math.floor(intervalMS / 1000 / 60);
 69	  // Use a minimum of 5m to make sure we have enough data to perform `irate` calculations, which
 70	  // require 2 data points each. Otherwise, there could be gaps in the graph.
 71	  const interval: Variable = { value: `${Math.max(intervalMinutes, 5)}m` };
 72	  // Add these last to ensure they are applied after other variable substitutions (because the other
 73	  // variable substitutions may result in interval variables like $__interval being inserted)
 74	  intervalVariableRegExps.forEach((k) => (allVariables[k] = interval));
 75	
 76	  let result = template;
 77	  _.each(allVariables, (v, k) => {
 78	    const re = new RegExp(`\\$${k}`, 'g');
 79	    if (result.match(re)) {
 80	      if (v.isLoading) {
 81	        result = undefined;
 82	        return false;
 83	      }
 84	      const replacement =
 85	        v.value === MONITORING_DASHBOARDS_VARIABLE_ALL_OPTION_KEY ? '.+' : v.value || '';
 86	      result = result.replace(re, replacement);
 87	    }
 88	  });
 89	
 90	  return result;
 91	};
 92	
 93	const LegacyDashboardsVariableOption = ({ value, isSelected, ...rest }) =>
 94	  isIntervalVariable(String(value)) ? (
 95	    <Tooltip content={value}>
 96	      <SelectOption value={value} isSelected={isSelected || false}>
 97	        Auto interval
 98	      </SelectOption>
 99	    </Tooltip>
100	  ) : (
101	    <SelectOption value={value} isSelected={isSelected || false} {...rest}>
102	      {value === MONITORING_DASHBOARDS_VARIABLE_ALL_OPTION_KEY ? 'All' : value}
103	    </SelectOption>
104	  );
105	
106	const LegacyDashboardsVariableDropdown: React.FC<VariableDropdownProps> = ({
107	  id,
108	  name,
109	  namespace,
110	  perspective,
111	}) => {
112	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
113	
114	  const timespan = useSelector((state: MonitoringState) =>
115	    getLegacyObserveState(perspective, state)?.getIn(['dashboards', perspective, 'timespan']),
116	  );
117	
118	  const variables = useSelector((state: MonitoringState) =>
119	    getLegacyObserveState(perspective, state)?.getIn(['dashboards', perspective, 'variables']),
120	  );
121	  const variable = variables.toJS()[name];
122	  const query = evaluateVariableTemplate(variable.query, variables, timespan);
123	
124	  const dispatch = useDispatch();
125	
126	  // eslint-disable-next-line react-hooks/exhaustive-deps
127	  const safeFetch = React.useCallback(useSafeFetch(), []);
128	
129	  const [isError, setIsError] = React.useState(false);
130	
131	  const customDataSourceName = variable?.datasource?.name;
132	  const [extensions, extensionsResolved] = useResolvedExtensions<DataSource>(isDataSource);
133	  const hasExtensions = !_.isEmpty(extensions);
134	
135	  const getURL = React.useCallback(
136	    async (prometheusProps) => {
137	      try {
138	        if (!customDataSourceName) {
139	          return getPrometheusURL(prometheusProps, perspective);
140	        } else if (extensionsResolved && hasExtensions) {
141	          const extension = extensions.find(
142	            (ext) => ext?.properties?.contextId === 'monitoring-dashboards',
143	          );
144	          const getDataSource = extension?.properties?.getDataSource;
145	          const dataSource = await getDataSource?.(customDataSourceName);
146	
147	          if (!dataSource || !dataSource.basePath) {
148	            setIsError(true);
149	            return;
150	          }
151	          return getPrometheusURL(prometheusProps, perspective, dataSource?.basePath);
152	        }
153	      } catch (error) {
154	        // eslint-disable-next-line no-console
155	        console.error(error);
156	        setIsError(true);
157	      }
158	    },
159	    [customDataSourceName, extensions, extensionsResolved, hasExtensions, perspective],
160	  );
161	
162	  React.useEffect(() => {
163	    if (!query) {
164	      return;
165	    }
166	    // Convert label_values queries to something Prometheus can handle
167	    // TODO: Once the Prometheus /series endpoint is available through the API proxy, this should
168	    // be converted to use that instead
169	    const prometheusQuery = query.replace(/label_values\((.*), (.*)\)/, 'count($1) by ($2)');
170	
171	    const timeRanges = getTimeRanges(timespan);
172	    const newOptions = new Set<string>();
173	    let abortError = false;
174	    dispatch(dashboardsPatchVariable(name, { isLoading: true }, perspective));
175	    Promise.allSettled(
176	      timeRanges.map(async (timeRange) => {
177	        const prometheusProps = {
178	          endpoint: PrometheusEndpoint.QUERY_RANGE,
179	          query: prometheusQuery,
180	          samples: Math.ceil(DEFAULT_GRAPH_SAMPLES / timeRanges.length),
181	          timeout: '60s',
182	          timespan: timeRange.duration,
183	          namespace: perspective === 'dev' ? namespace : '',
184	          endTime: timeRange.endTime,
185	        };
186	        return getURL(prometheusProps).then((url) =>
187	          safeFetch(url)
188	            .then(({ data }) => {
189	              const responseOptions = _.flatMap(data?.result, ({ metric }) => _.values(metric));
190	              responseOptions.forEach(newOptions.add, newOptions);
191	            })
192	            .catch((err) => {
193	              if (isTimeoutError(err)) {
194	                // eslint-disable-next-line no-console
195	                console.error(
196	                  `Timed Out Retrieving Labels from ${new Date(
197	                    timeRange.endTime - QUERY_CHUNK_SIZE,
198	                  ).toISOString()} - ${new Date(timeRange.endTime).toISOString()} for ${query}`,
199	                );
200	              } else if (err.name === 'AbortError') {
201	                abortError = true;
202	              } else {
203	                // eslint-disable-next-line no-console
204	                console.error(err);
205	              }
206	            }),
207	        );
208	      }),
209	    ).then((results) => {
210	      const errors = results.filter((result) => result.status === 'rejected').length > 0;
211	      if (newOptions.size > 0 || !errors) {
212	        setIsError(false);
213	        // Options were found or no options were found but that wasn't in error
214	        const newOptionArray = Array.from(newOptions).sort();
215	        dispatch(dashboardsVariableOptionsLoaded(name, newOptionArray, perspective));
216	      } else {
217	        // No options were found, and there were errors (timeouts or other) in fetching the data
218	        dispatch(dashboardsPatchVariable(name, { isLoading: false }, perspective));
219	        if (!abortError) {
220	          setIsError(true);
221	        }
222	      }
223	    });
224	  }, [
225	    perspective,
226	    dispatch,
227	    getURL,
228	    name,
229	    namespace,
230	    query,
231	    safeFetch,
232	    timespan,
233	    variable.includeAll,
234	    variable.options,
235	  ]);
236	
237	  React.useEffect(() => {
238	    if (variable.value && variable.value !== getQueryArgument(name)) {
239	      if (perspective === 'dev' && name !== 'namespace') {
240	        setQueryArgument(name, variable.value);
241	      } else if (perspective === 'admin' || perspective === 'virtualization-perspective') {
242	        setQueryArgument(name, variable.value);
243	      }
244	    }
245	  }, [perspective, name, variable.value]);
246	
247	  const onChange = React.useCallback(
248	    (v: string) => {
249	      if (v !== variable.value) {
250	        if (perspective === 'dev' && name !== 'namespace') {
251	          setQueryArgument(name, v);
252	        } else if (perspective === 'admin' || perspective === 'virtualization-perspective') {
253	          setQueryArgument(name, v);
254	        }
255	        dispatch(dashboardsPatchVariable(name, { value: v }, perspective));
256	      }
257	    },
258	    [perspective, dispatch, name, variable.value],
259	  );
260	
261	  if (variable.isHidden || (!isError && _.isEmpty(variable.options))) {
262	    return null;
263	  }
264	
265	  const items = (
266	    variable.includeAll
267	      ? [{ value: MONITORING_DASHBOARDS_VARIABLE_ALL_OPTION_KEY, children: 'All' }]
268	      : []
269	  ).concat(
270	    _.map(variable.options, (option) => ({
271	      value: option,
272	      children: option,
273	    })),
274	  );
275	
276	  return (
277	    <div
278	      className="form-group monitoring-dashboards__dropdown-wrap"
279	      data-test={`${name.toLowerCase()}-dropdown`}
280	    >
281	      <label htmlFor={`${id}-dropdown`} className="monitoring-dashboards__dropdown-title">
282	        {name}
283	      </label>
284	      {isError ? (
285	        <Select
286	          toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
287	            <MenuToggle
288	              ref={toggleRef}
289	              className="monitoring-dashboards__dropdown-button"
290	              isDisabled={true}
291	              onClick={(e) => e.preventDefault()}
292	            >
293	              <RedExclamationCircleIcon /> {t('Error loading options')}
294	            </MenuToggle>
295	          )}
296	        />
297	      ) : (
298	        <SingleTypeaheadDropdown
299	          items={items}
300	          onChange={onChange}
301	          OptionComponent={LegacyDashboardsVariableOption}
302	          selectedKey={variable.value}
303	          hideClearButton
304	          resizeToFit
305	          placeholder={t('Select a dashboard from the dropdown')}
306	        />
307	      )}
308	    </div>
309	  );
310	};
311	
312	export const LegacyDashboardsAllVariableDropdowns: React.FC = () => {
313	  const [namespace] = useActiveNamespace();
314	  const { perspective } = usePerspective();
315	  const variables = useSelector((state: MonitoringState) =>
316	    getLegacyObserveState(perspective, state)?.getIn(['dashboards', perspective, 'variables']),
317	  );
318	
319	  if (!variables) {
320	    return null;
321	  }
322	
323	  return (
324	    <>
325	      {variables.keySeq().map((name: string) => (
326	        <LegacyDashboardsVariableDropdown
327	          key={name}
328	          id={name}
329	          name={name}
330	          namespace={namespace}
331	          perspective={perspective}
332	        />
333	      ))}
334	    </>
335	  );
336	};
337	
338	type Variable = {
339	  isHidden?: boolean;
340	  isLoading?: boolean;
341	  options?: string[];
342	  query?: string;
343	  value?: string;
344	};
345	
346	type VariableDropdownProps = {
347	  id: string;
348	  name: string;
349	  perspective: Perspective;
350	  namespace?: string;
351	};

