153	          const dataSource = await getDataSource?.(customDataSourceName);
154	
155	          if (!dataSource || !dataSource.basePath) {
156	            setIsError(true);
157	            return;
158	          }
159	          return getPrometheusURL(prometheusProps, perspective, dataSource?.basePath);
160	        }
161	      } catch (error) {
162	        // eslint-disable-next-line no-console
163	        console.error(error);
164	        setIsError(true);
165	      }
166	    },
167	    [customDataSourceName, extensions, extensionsResolved, hasExtensions, perspective],
168	  );
169	
170	  React.useEffect(() => {
171	    if (!query) {
172	      return;
173	    }
174	    // Convert label_values queries to something Prometheus can handle
175	    // TODO: Once the Prometheus /series endpoint is available through the API proxy, this should
176	    // be converted to use that instead
177	    const prometheusQuery = query.replace(/label_values\((.*), (.*)\)/, 'count($1) by ($2)');
178	
179	    const timeRanges = getTimeRanges(timespan);
180	    const newOptions = new Set<string>();
181	    let abortError = false;
182	    dispatch(dashboardsPatchVariable(name, { isLoading: true }, perspective));
