 45	
 46	const intervalVariableRegExps = ['__interval', '__rate_interval', '__auto_interval_[a-z]+'];
 47	
 48	const isIntervalVariable = (itemKey: string): boolean =>
 49	  _.some(intervalVariableRegExps, (re) => itemKey?.match(new RegExp(`\\$${re}`, 'g')));
 50	
 51	export const evaluateVariableTemplate = (
 52	  template: string,
 53	  variables: ImmutableMap<string, Variable>,
 54	  timespan: number,
 55	): string => {
 56	  if (_.isEmpty(template)) {
 57	    return undefined;
 58	  }
 59	
 60	  const range: Variable = { value: `${Math.floor(timespan / 1000)}s` };
 61	  const allVariables = {
 62	    ...variables.toJS(),
 63	    __range: range,
 64	    /* eslint-disable camelcase */
 65	    __range_ms: range,
 66	    __range_s: range,
 67	    /* eslint-enable camelcase */
 68	  };
 69	
 70	  // Handle the special "interval" variables
 71	  const intervalMS = timespan / DEFAULT_GRAPH_SAMPLES;
 72	  const intervalMinutes = Math.floor(intervalMS / 1000 / 60);
 73	  // Use a minimum of 5m to make sure we have enough data to perform `irate` calculations, which
 74	  // require 2 data points each. Otherwise, there could be gaps in the graph.
 75	  const interval: Variable = { value: `${Math.max(intervalMinutes, 5)}m` };
 76	  // Add these last to ensure they are applied after other variable substitutions (because the other
 77	  // variable substitutions may result in interval variables like $__interval being inserted)
 78	  intervalVariableRegExps.forEach((k) => (allVariables[k] = interval));
 79	
 80	  let result = template;
 81	  _.each(allVariables, (v, k) => {
 82	    const re = new RegExp(`\\$${k}`, 'g');
 83	    if (result.match(re)) {
 84	      if (v.isLoading) {
 85	        result = undefined;
 86	        return false;
 87	      }
 88	      const replacement =
 89	        v.value === MONITORING_DASHBOARDS_VARIABLE_ALL_OPTION_KEY ? '.+' : v.value || '';
 90	      result = result.replace(re, replacement);
 91	    }
 92	  });
 93	
 94	  return result;
 95	};
