102	          Auto interval
103	        </SelectOption>
104	      </SelectList>
105	    </Tooltip>
106	  ) : (
107	    <SelectList>
108	      <SelectOption value={value} isSelected={isSelected || false} {...rest}>
109	        {value === MONITORING_DASHBOARDS_VARIABLE_ALL_OPTION_KEY ? 'All' : value}
110	      </SelectOption>
111	    </SelectList>
112	  );
