114	const LegacyDashboardsVariableDropdown: React.FC<VariableDropdownProps> = ({
115	  id,
116	  name,
117	  namespace,
118	  perspective,
119	}) => {
120	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
121	
122	  const timespan = useSelector((state: MonitoringState) =>
123	    getLegacyObserveState(perspective, state)?.getIn(['dashboards', perspective, 'timespan']),
124	  );
125	
126	  const variables = useSelector((state: MonitoringState) =>
127	    getLegacyObserveState(perspective, state)?.getIn(['dashboards', perspective, 'variables']),
128	  );
129	  const variable = variables.toJS()[name];
130	  const query = evaluateVariableTemplate(variable.query, variables, timespan);
131	
132	  const dispatch = useDispatch();
133	
134	  // eslint-disable-next-line react-hooks/exhaustive-deps
135	  const safeFetch = React.useCallback(useSafeFetch(), []);
136	
137	  const [isError, setIsError] = React.useState(false);
138	
139	  const customDataSourceName = variable?.datasource?.name;
140	  const [extensions, extensionsResolved] = useResolvedExtensions<DataSource>(isDataSource);
141	  const hasExtensions = !_.isEmpty(extensions);
142	
143	  const getURL = React.useCallback(
144	    async (prometheusProps) => {
145	      try {
146	        if (!customDataSourceName) {
147	          return getPrometheusURL(prometheusProps, perspective);
148	        } else if (extensionsResolved && hasExtensions) {
149	          const extension = extensions.find(
150	            (ext) => ext?.properties?.contextId === 'monitoring-dashboards',
151	          );
152	          const getDataSource = extension?.properties?.getDataSource;
153	          const dataSource = await getDataSource?.(customDataSourceName);
154	
155	          if (!dataSource || !dataSource.basePath) {
156	            setIsError(true);
157	            return;
158	          }
159	          return getPrometheusURL(prometheusProps, perspective, dataSource?.basePath);
160	        }
161	      } catch (error) {
162	        // eslint-disable-next-line no-console
163	        console.error(error);
164	        setIsError(true);
165	      }
166	    },
167	    [customDataSourceName, extensions, extensionsResolved, hasExtensions, perspective],
168	  );
169	
170	  React.useEffect(() => {
171	    if (!query) {
172	      return;
173	    }
174	    // Convert label_values queries to something Prometheus can handle
175	    // TODO: Once the Prometheus /series endpoint is available through the API proxy, this should
176	    // be converted to use that instead
177	    const prometheusQuery = query.replace(/label_values\((.*), (.*)\)/, 'count($1) by ($2)');
178	
179	    const timeRanges = getTimeRanges(timespan);
180	    const newOptions = new Set<string>();
181	    let abortError = false;
182	    dispatch(dashboardsPatchVariable(name, { isLoading: true }, perspective));
183	    Promise.allSettled(
184	      timeRanges.map(async (timeRange) => {
185	        const prometheusProps = {
186	          endpoint: PrometheusEndpoint.QUERY_RANGE,
187	          query: prometheusQuery,
188	          samples: Math.ceil(DEFAULT_GRAPH_SAMPLES / timeRanges.length),
189	          timeout: '60s',
190	          timespan: timeRange.duration,
191	          namespace: perspective === 'dev' ? namespace : '',
192	          endTime: timeRange.endTime,
193	        };
194	        return getURL(prometheusProps).then((url) =>
195	          safeFetch(url)
196	            .then(({ data }) => {
197	              const responseOptions = _.flatMap(data?.result, ({ metric }) => _.values(metric));
198	              responseOptions.forEach(newOptions.add, newOptions);
199	            })
200	            .catch((err) => {
201	              if (isTimeoutError(err)) {
202	                // eslint-disable-next-line no-console
203	                console.error(
204	                  `Timed Out Retrieving Labels from ${new Date(
205	                    timeRange.endTime - QUERY_CHUNK_SIZE,
206	                  ).toISOString()} - ${new Date(timeRange.endTime).toISOString()} for ${query}`,
207	                );
208	              } else if (err.name === 'AbortError') {
209	                abortError = true;
210	              } else {
211	                // eslint-disable-next-line no-console
212	                console.error(err);
213	              }
214	            }),
215	        );
216	      }),
217	    ).then((results) => {
218	      const errors = results.filter((result) => result.status === 'rejected').length > 0;
219	      if (newOptions.size > 0 || !errors) {
220	        setIsError(false);
221	        // Options were found or no options were found but that wasn't in error
222	        const newOptionArray = Array.from(newOptions).sort();
223	        dispatch(dashboardsVariableOptionsLoaded(name, newOptionArray, perspective));
224	      } else {
225	        // No options were found, and there were errors (timeouts or other) in fetching the data
226	        dispatch(dashboardsPatchVariable(name, { isLoading: false }, perspective));
227	        if (!abortError) {
228	          setIsError(true);
229	        }
230	      }
231	    });
232	  }, [
233	    perspective,
234	    dispatch,
235	    getURL,
236	    name,
237	    namespace,
238	    query,
239	    safeFetch,
240	    timespan,
241	    variable.includeAll,
242	    variable.options,
243	  ]);
244	
245	  React.useEffect(() => {
246	    if (variable.value && variable.value !== getQueryArgument(name)) {
247	      if (perspective === 'dev' && name !== 'namespace') {
248	        setQueryArgument(name, variable.value);
249	      } else if (perspective === 'admin' || perspective === 'virtualization-perspective') {
250	        setQueryArgument(name, variable.value);
251	      }
252	    }
253	  }, [perspective, name, variable.value]);
254	
255	  const onChange = React.useCallback(
256	    (v: string) => {
257	      if (v !== variable.value) {
258	        if (perspective === 'dev' && name !== 'namespace') {
259	          setQueryArgument(name, v);
260	        } else if (perspective === 'admin' || perspective === 'virtualization-perspective') {
261	          setQueryArgument(name, v);
262	        }
263	        dispatch(dashboardsPatchVariable(name, { value: v }, perspective));
264	      }
265	    },
266	    [perspective, dispatch, name, variable.value],
267	  );
268	
269	  if (variable.isHidden || (!isError && _.isEmpty(variable.options))) {
