271	  }
272	
273	  const items = (
274	    variable.includeAll
275	      ? [{ value: MONITORING_DASHBOARDS_VARIABLE_ALL_OPTION_KEY, children: 'All' }]
276	      : []
277	  ).concat(
278	    _.map(variable.options, (option) => ({
279	      value: option,
280	      children: option,
281	    })),
282	  );
283	
284	  return (
285	    <div
286	      className="form-group monitoring-dashboards__dropdown-wrap"
287	      data-test={`${name.toLowerCase()}-dropdown`}
288	    >
289	      <label htmlFor={`${id}-dropdown`} className="monitoring-dashboards__dropdown-title">
290	        {name}
291	      </label>
292	      {isError ? (
293	        <Select
294	          toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
295	            <MenuToggle
296	              ref={toggleRef}
297	              className="monitoring-dashboards__dropdown-button"
298	              isDisabled={true}
299	              onClick={(e) => e.preventDefault()}
300	              icon={<RedExclamationCircleIcon />}
301	            >
302	              {t('Error loading options')}
303	            </MenuToggle>
304	          )}
305	        />
