308	          items={items}
309	          onChange={onChange}
310	          OptionComponent={LegacyDashboardsVariableOption}
311	          selectedKey={variable.value}
312	          hideClearButton
313	          resizeToFit
314	          placeholder={t('Select a dashboard from the dropdown')}
315	        />
316	      )}
317	    </div>
318	  );
